const items = $input.all();
const results = [];

for (const item of items) {
  const fields = item.json.fields || item.json;
  const emailArr = fields.Email || [];
  const email = Array.isArray(emailArr) ? emailArr[0] : emailArr;
  const nombreArr = fields.Nombre || [];
  const nombre = Array.isArray(nombreArr) ? nombreArr[0] : nombreArr;
  const alumnoId = item.json.id || fields.id || '';
  const idioma = (fields.Idioma || '').toString().toLowerCase();

  if (!email) continue;

  const baseFormUrl = 'https://tally.so/r/xXrvao';
  const formOnboarding = baseFormUrl
    + '?fullname=' + encodeURIComponent(nombre || '')
    + '&email=' + encodeURIComponent(email)
    + '&alumnoId=' + encodeURIComponent(alumnoId);
  const displayName = nombre || 'Alumno/a';
  const isEnglish = idioma && !idioma.includes('espa');
  const subject = isEnglish ? 'ProEv - Welcome to the course!' : 'ProEv - Bienvenido/a al curso!';

  results.push({
    json: {
      email,
      nombre: displayName,
      alumnoId,
      formOnboarding,
      idioma,
      subject
    }
  });
}

return results.length > 0 ? results : [{ json: { skip: true } }];

const prev = $('Tiene Email?').item.json;
const inboxId = $input.first().json.id || '';
const alumnoId = prev.alumnoId;

const trackPixel = 'https://hooks.dravaautomations.com/webhook/email-track?alumno=' + alumnoId + '&tipo=onboarding&inboxId=' + inboxId;
const formOnboarding = prev.formOnboarding;
const displayName = prev.nombre;
const isEnglish = prev.idioma && !prev.idioma.toLowerCase().includes('espa');

// Link tracking URL
const trackedFormUrl = 'https://hooks.dravaautomations.com/webhook/email-click?alumno=' + alumnoId + '&tipo=onboarding&inboxId=' + inboxId + '&url=' + encodeURIComponent(formOnboarding);

const greeting = isEnglish ? 'Hi ' + displayName + '!' : '&iexcl;Hola ' + displayName + '!';
const headerBlock = '<div style="text-align:center;margin-bottom:30px"><div style="font-size:36px">&#127881;&#128131;</div><h1 style="color:#0C5A45;font-size:24px;margin:10px 0">' + greeting + '</h1></div>';

const buttonText = isEnglish ? 'COMPLETE FINAL DETAILS' : 'COMPLETAR DATOS FINALES';
const buttonStyle = 'background-color:#0C5A45;color:#fff;font-size:14px;font-weight:600;text-decoration:none;padding:15px 30px;border-radius:3px;display:inline-block;letter-spacing:0.5px;';
const ctaButton = '<table border="0" cellspacing="0" cellpadding="0" width="100%"><tr><td align="center" style="padding:20px 0;"><a href="' + trackedFormUrl + '" target="_blank" style="' + buttonStyle + '">' + buttonText + '</a></td></tr></table>';

let bodyContent;
if (isEnglish) {
  bodyContent = '<p style="color:#1A1A1A;line-height:1.7;font-size:15px">Your payment has been confirmed! You are now officially part of our bachata course.</p>' +
    '<p style="color:#1A1A1A;line-height:1.7;font-size:15px">We are very excited to have you with us. We just need a few final details to prepare everything:</p>' +
    ctaButton +
    '<p style="color:#888;font-size:14px;text-align:center">T-shirt size, emergency contact details, etc.</p>' +
    '<div style="background:#f0f7f4;border-radius:8px;padding:20px;margin:25px 0">' +
    '<p style="color:#0C5A45;font-weight:600;margin:0 0 8px">Next steps:</p>' +
    '<ol style="color:#1A1A1A;line-height:1.8;margin:0;padding-left:20px">' +
    '<li>Fill out the form above</li>' +
    '<li>We will send you the complete course information (schedules, location, what to bring)</li>' +
    '<li>See you soon!</li></ol></div>';
} else {
  bodyContent = '<p style="color:#1A1A1A;line-height:1.7;font-size:15px">&iexcl;Tu pago ha sido confirmado! Ya eres oficialmente parte de nuestro curso de bachata.</p>' +
    '<p style="color:#1A1A1A;line-height:1.7;font-size:15px">Estamos muy emocionados de tenerte con nosotros. Solo necesitamos unos &uacute;ltimos datos para preparar todo:</p>' +
    ctaButton +
    '<p style="color:#888;font-size:14px;text-align:center">Talla de camiseta, datos de contacto de emergencia, etc.</p>' +
    '<div style="background:#f0f7f4;border-radius:8px;padding:20px;margin:25px 0">' +
    '<p style="color:#0C5A45;font-weight:600;margin:0 0 8px">Pr&oacute;ximos pasos:</p>' +
    '<ol style="color:#1A1A1A;line-height:1.8;margin:0;padding-left:20px">' +
    '<li>Rellena el formulario de arriba</li>' +
    '<li>Te enviaremos la informaci&oacute;n completa del curso (horarios, lugar, qu&eacute; traer)</li>' +
    '<li>&iexcl;Nos vemos pronto!</li></ol></div>';
}

const signature = '<p style="margin:25px 0 0;text-align:center;font-size:15px;color:#1A1A1A;"><strong>Alonso &amp; Noelia</strong></p>';
const socialLinks = '<p style="margin-bottom:15px;"><a href="https://www.instagram.com/alonsoynoelia" style="color:#1A1A1A;text-decoration:none;font-size:11px;font-weight:600;letter-spacing:1px;margin:0 8px;">INSTAGRAM</a> <a href="https://www.youtube.com/@alonsoynoelia" style="color:#1A1A1A;text-decoration:none;font-size:11px;font-weight:600;letter-spacing:1px;margin:0 8px;">YOUTUBE</a> <a href="https://alonsoynoeliaonline.com" style="color:#1A1A1A;text-decoration:none;font-size:11px;font-weight:600;letter-spacing:1px;margin:0 8px;">WEB</a></p>';

const subject = prev.subject;

const htmlBody = '<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>' + subject + '</title><style>body{margin:0;padding:0;width:100%!important;background-color:#F6F3EE;font-family:Inter,Helvetica Neue,Arial,sans-serif;color:#1A1A1A}@media screen and (max-width:520px){.wrapper{width:100%!important}.inner{padding:30px 20px!important}}</style></head><body style="margin:0;padding:0;background-color:#F6F3EE;"><center><table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color:#F6F3EE;"><tr><td align="center" valign="top" style="padding:20px;"><table class="wrapper" width="500" border="0" cellpadding="0" cellspacing="0" style="width:500px;max-width:500px;margin:0 auto;"><tr><td align="center" style="padding-bottom:25px;"><img src="https://sawa-dev-2-storage-bucket.storage.googleapis.com/profiles/nx0mtgi3zeb8acxp-d7a42.png" alt="Alonso y Noelia" width="160" style="display:block;"></td></tr><tr><td style="background-color:#fff;border-radius:4px;overflow:hidden;box-shadow:0 5px 15px rgba(0,0,0,0.03);"><table width="100%" border="0" cellpadding="0" cellspacing="0"><tr><td class="inner" style="padding:40px 30px;font-size:15px;line-height:1.7;color:#1A1A1A;">' + headerBlock + bodyContent + signature + '</td></tr></table></td></tr><tr><td style="padding:25px 0;text-align:center;">' + socialLinks + '<p style="font-size:10px;color:#A9A9A9;margin:0;">&copy; 2026 Alonso &amp; Noelia.</p></td></tr></table></td></tr></table></center><img src="' + trackPixel + '" width="1" height="1" style="display:none" alt=""></body></html>';

return [{
  json: {
    email: prev.email,
    nombre: displayName,
    alumnoId,
    inboxId,
    trackPixel,
    formOnboarding,
    idioma: prev.idioma,
    subject,
    htmlBody
  }
}];

const llmOutput = $json.output || {};
const original = $('Traducir?').item.json;
return [{
  json: {
    email: original.email,
    nombre: original.nombre,
    alumnoId: original.alumnoId,
    inboxId: original.inboxId,
    subject: llmOutput.subject || original.subject,
    htmlBody: llmOutput.htmlBody || original.htmlBody,
    trackPixel: original.trackPixel,
    idioma: original.idioma
  }
}];
